import { useState, useEffect } from "react";
import { useSelector } from "react-redux";

function Enrollments() {
  const [enrollments, setEnrollments] = useState([]);
  const [courses, setCourses] = useState([]);
  const [selectedCourse, setSelectedCourse] = useState("");
  const user = useSelector((state) => state.auth.user);

  useEffect(() => {
    fetch("http://localhost:3001/enrollments?studentId=" + user.id)
      .then((res) => res.json())
      .then((data) => setEnrollments(data));
    fetch("http://localhost:3001/courses")
      .then((res) => res.json())
      .then((data) => setCourses(data));
  }, [user.id]);

  async function handleEnroll(e) {
    e.preventDefault();
    if (!selectedCourse) {
      alert("Please select a course.");
      return;
    }

    const newEnrollment = { studentId: user.id, courseId: parseInt(selectedCourse) };

    const response = await fetch("http://localhost:3001/enrollments", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(newEnrollment),
    });

    if (response.ok) {
      const enrollment = await response.json();
      setEnrollments([...enrollments, enrollment]);
    }
  }

  return (
    <div>
      <h1>My Enrollments (Students Only)</h1>
      {user.role === "student" && (
        <form onSubmit={handleEnroll}>
          <select
            value={selectedCourse}
            onChange={(e) => setSelectedCourse(e.target.value)}
          >
            <option value="">-- Choose a course --</option>
            {courses.map((course) => (
              <option key={course.id} value={course.id}>
                {course.name}
              </option>
            ))}
          </select>
          <button type="submit">Enroll</button>
        </form>
      )}
      <ul>
        {enrollments.map((enrollment) => (
          <li key={enrollment.id}>
            Course ID: {enrollment.courseId}
          </li>
        ))}
      </ul>
    </div>
  );
}

export default Enrollments;
